import ollama, json, re

SYSTEM = (
    "You are an assistant that answers in JSON. "
    "Always respond with: {\"answer\": \"...\", \"confidence\": 0.0-1.0}"
)

def structured_query(question: str, model: str = "llama3.2") -> dict:
    """Query local Ollama model and parse structured JSON response."""
    messages = [
        {"role": "system", "content": SYSTEM},
        {"role": "user", "content": question},
    ]
    full_text = ""
    for chunk in ollama.chat(model=model, messages=messages, stream=True):
        token = chunk["message"]["content"]
        full_text += token
        print(token, end="", flush=True)
    print()

    match = re.search(r"\{.*?\}", full_text, re.DOTALL)
    if not match:
        return {"answer": full_text.strip(), "confidence": 0.0}
    try:
        return json.loads(match.group())
    except json.JSONDecodeError:
        return {"answer": full_text.strip(), "confidence": 0.0}


questions = [
    "What year was Python first released?",
    "Name the three primary colors of light.",
]

for q in questions:
    print(f"Q: {q}")
    result = structured_query(q)
    print(f"A: {result.get('answer')} (confidence={result.get('confidence')})")
    print()

import ollama, json

EXTRACT_PROMPT = (
    "Extract the following fields from the contract excerpt.\n"
    "Return a JSON object with keys: termination_date, liability_cap, jurisdiction.\n"
    "Use null for any field not mentioned.\n\n"
    "Contract excerpt:\n{text}"
)

def extract_fields(text: str, model: str = "mistral") -> dict:
    prompt = EXTRACT_PROMPT.format(text=text[:3000])
    resp = ollama.generate(
        model=model,
        prompt=prompt,
        options={"temperature": 0.0, "num_predict": 256},
        stream=False,
    )
    raw = resp["response"].strip()
    # Strip markdown fences if present
    if raw.startswith("```"):
        raw = raw.split("```")[1]
        if raw.startswith("json"):
            raw = raw[4:]
    raw = raw.strip()
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        return {"termination_date": None, "liability_cap": None, "jurisdiction": None}


sample_text = (
    "This Agreement shall terminate on December 31, 2026. "
    "Liability of either party is capped at $500,000 USD. "
    "This Agreement is governed by the laws of the State of New York."
)

fields = extract_fields(sample_text)
print(json.dumps(fields, indent=2))
